mapper.update:
UPDATE cf_account
SET user_id = #{userId}, account_book_id = #{accountBookId}, asset_account_id = #{assetAccountId}, category_id = #{categoryId}, type = #{type}, amount = #{amount}, remark = #{remark}, image_url = #{imageUrl}, location = #{location}, happened_at = #{happenedAt}, updated_at = #{updatedAt}
WHERE id = #{id}

mapper.select:
SELECT COALESCE(SUM(amount), 0)
FROM cf_account
WHERE user_id = #{userId}
  AND type = #{type}
  AND happened_at >= #{startDate}
  AND happened_at <= #{endDate}

SELECT COUNT(*)
FROM cf_account
WHERE user_id = #{userId}
  AND happened_at >= #{startDate}
  AND happened_at <= #{endDate}

SELECT c.name AS category_name,
       SUM(a.amount) AS total_amount,
       COUNT(*) AS count
FROM cf_account a
LEFT JOIN cf_account_category c ON a.category_id = c.id
WHERE a.user_id = #{userId}
  AND a.type = #{type}
  AND a.happened_at >= #{startDate}
  AND a.happened_at <= #{endDate}
GROUP BY c.id, c.name
ORDER BY total_amount DESC

SELECT * FROM cf_account
WHERE user_id = #{userId}
ORDER BY happened_at DESC
LIMIT #{limit}
